/**
 * Generate Dify firewall config (cloud-only).
 *
 * Data source: https://docs.dify.ai/
 *
 * Dify uses Bearer token authentication via Authorization header.
 * App API key format: app- + 24 alphanumeric chars = 28 total.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.dify.ai/";
// Format: app- + 24 alphanumeric chars (total 28)
const PLACEHOLDER_VALUE = "app-CoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Dify API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:dify",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const difyFirewall = {",
    '  name: "dify",',
    '  description: "Dify API",',
    "  placeholders: {",
    `    DIFY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.dify.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DIFY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Dify firewall config...");
  const ts = generateTypeScript();
  writeOutput("dify", ts, import.meta.dirname);
}
